/**
 * Revenue Engine Types
 *
 * Tracks real revenue generated BY the agents, not platform fees.
 * The agents ARE the business — they close deals, deliver services,
 * process payments, and generate actual income.
 */

import type { OrgId } from "../tenants/types.js";

// ── Revenue Streams ──────────────────────────────────────────────────────────

export const REVENUE_SOURCES = [
	"client_payment",       // Direct client payment for services
	"subscription",         // Recurring client subscription
	"product_sale",         // Digital/physical product sale
	"lead_conversion",      // Commission from lead conversion
	"affiliate",            // Affiliate commission
	"ad_revenue",           // Ad or sponsorship revenue
	"consulting_fee",       // Consulting/advisory session fee
	"service_delivery",     // One-time service delivery
	"marketplace_sale",     // Sale via marketplace (Stripe, Gumroad, etc.)
	"invoice_paid",         // Invoice payment received
] as const;
export type RevenueSource = (typeof REVENUE_SOURCES)[number];

// ── Revenue Event ────────────────────────────────────────────────────────────

export interface RevenueEvent {
	id: string;
	orgId: OrgId;
	entityId?: string;
	agentId: string;
	source: RevenueSource;
	amountCents: number;
	currency: string;
	/** Who paid (client name, email, company) */
	payer: string;
	description: string;
	/** External payment reference (Stripe charge ID, invoice #, etc.) */
	externalRef?: string;
	metadata: Record<string, string>;
	timestamp: Date;
}

// ── Revenue Summary ──────────────────────────────────────────────────────────

export interface RevenueSummary {
	orgId: OrgId;
	periodStart: Date;
	periodEnd: Date;
	totalRevenueCents: number;
	totalExpensesCents: number;
	netIncomeCents: number;
	bySource: Record<string, number>;
	byAgent: Record<string, number>;
	transactionCount: number;
}

// ── Revenue Goal ─────────────────────────────────────────────────────────────

export interface RevenueGoal {
	id: string;
	orgId: OrgId;
	targetAmountCents: number;
	currentAmountCents: number;
	period: "daily" | "weekly" | "monthly" | "quarterly" | "annual";
	startDate: Date;
	endDate: Date;
	status: "on_track" | "behind" | "ahead" | "achieved";
}

// ── Client / Customer ────────────────────────────────────────────────────────

export interface Client {
	id: string;
	orgId: OrgId;
	name: string;
	email: string;
	company?: string;
	source: string;
	/** Agent that acquired this client */
	acquiredByAgentId?: string;
	lifetimeValueCents: number;
	status: "lead" | "prospect" | "active" | "churned";
	tags: string[];
	metadata: Record<string, string>;
	createdAt: Date;
	lastInteractionAt: Date;
}

// ── Invoice ──────────────────────────────────────────────────────────────────

export interface Invoice {
	id: string;
	orgId: OrgId;
	clientId: string;
	agentId: string;
	lineItems: InvoiceLineItem[];
	subtotalCents: number;
	taxCents: number;
	totalCents: number;
	status: "draft" | "sent" | "paid" | "overdue" | "void";
	dueDate: Date;
	paidAt?: Date;
	stripeInvoiceId?: string;
	createdAt: Date;
}

export interface InvoiceLineItem {
	description: string;
	quantity: number;
	unitPriceCents: number;
	totalCents: number;
}

// ── Pipeline (deals in progress) ─────────────────────────────────────────────

export interface Deal {
	id: string;
	orgId: OrgId;
	clientId: string;
	agentId: string;
	name: string;
	valueCents: number;
	stage: "lead" | "qualified" | "proposal" | "negotiation" | "closed_won" | "closed_lost";
	probability: number;
	expectedCloseDate: Date;
	notes: string;
	createdAt: Date;
	updatedAt: Date;
}
